:param shell_complete: A function that returns custom shell
    completions. Used instead of the param's type completion if
    given. Takes ``ctx, param, incomplete`` and must return a list
    of :class:`~click.shell_completion.CompletionItem` or a list of
    strings.
:param deprecated: If ``True`` or non-empty string, issues a message
                    indicating that the argument is deprecated and highlights
                    its deprecation in --help. The message can be customized
                    by using a string as the value. A deprecated parameter
                    cannot be required, a ValueError will be raised otherwise.

.. versionchanged:: 8.2.0
    Introduction of ``deprecated``.

.. versionchanged:: 8.2
    Adding duplicate parameter names to a :class:`~click.core.Command` will
    result in a ``UserWarning`` being shown.

.. versionchanged:: 8.2
    Adding duplicate parameter names to a :class:`~click.core.Command` will
    result in a ``UserWarning`` being shown.

.. versionchanged:: 8.0
    ``process_value`` validates required parameters and bounded
    ``nargs``, and invokes the parameter callback before returning
    the value. This allows the callback to validate prompts.
    ``full_process_value`` is removed.

.. versionchanged:: 8.0
    ``autocompletion`` is renamed to ``shell_complete`` and has new
    semantics described above. The old name is deprecated and will
    be removed in 8.1, until then it will be wrapped to match the
    new requirements.

.. versionchanged:: 8.0
    For ``multiple=True, nargs>1``, the default must be a list of
    tuples.

.. versionchanged:: 8.0
    Setting a default is no longer required for ``nargs>1``, it will
    default to ``None``. ``multiple=True`` or ``nargs=-1`` will
    default to ``()``.

.. versionchanged:: 7.1
    Empty environment variables are ignored rather than taking the
    empty string value. This makes it possible for scripts to clear
    variables if they can't unset them.

.. versionchanged:: 2.0
    Changed signature for parameter callback to also be passed the
    parameter. The old callback format will still work, but it will
    raise a warning to give you a chance to migrate the code easier.
"""

param_type_name = "parameter"

def __init__(
    self,
    param_decls: cabc.Sequence[str] | None = None,
    type: types.ParamType | t.Any | None = None,
    required: bool = False,
    default: t.Any | t.Callable[[], t.Any] | None = None,
    callback: t.Callable[[Context, Parameter, t.Any], t.Any] | None = None,
    nargs: int | None = None,
    multiple: bool = False,
    metavar: str | None = None,
    expose_value: bool = True,
    is_eager: bool = False,
    envvar: str | cabc.Sequence[str] | None = None,
    shell_complete: t.Callable[
        [Context, Parameter, str], list[CompletionItem] | list[str]
    ]
    | None = None,
    deprecated: bool | str = False,
) -> None:
    self.name: str | None
    self.opts: list[str]
    self.secondary_opts: list[str]
    self.name, self.opts, self.secondary_opts = self._parse_decls(
        param_decls or (), expose_value
    )
    self.type: types.ParamType = types.convert_type(type, default)

    # Default nargs to what the type tells us if we have that
    # information available.
    if nargs is None:
        if self.type.is_composite:
            nargs = self.type.arity
        else:
            nargs = 1

    self.required = required
    self.callback = callback
    self.nargs = nargs
    self.multiple = multiple
    self.expose_value = expose_value
    self.default = default
    self.is_eager = is_eager
    self.metavar = metavar
    self.envvar = envvar
    self._custom_shell_complete = shell_complete
    self.deprecated = deprecated

    if __debug__:
        if self.type.is_composite and nargs != self.type.arity:
            raise ValueError(
                f"'nargs' must be {self.type.arity} (or None) for"
                f" type {self.type!r}, but it was {nargs}."
            )

        # Skip no default or callable default.
        check_default = default if not callable(default) else None

        if check_default is not None:
            if multiple:
                try:
                    # Only check the first value against nargs.
                    check_default = next(_check_iter(check_default), None)
                except TypeError:
                    raise ValueError(
                        "'default' must be a list when 'multiple' is true."
                    ) from None

            # Can be None for multiple with empty default.
            if nargs != 1 and check_default is not None:
                try:
                    _check_iter(check_default)
                except TypeError:
                    if multiple:
                        message = (
                            "'default' must be a list of lists when 'multiple' is"
                            " true and 'nargs' != 1."
                        )
                    else:
                        message = "'default' must be a list when 'nargs' != 1."

                    raise ValueError(message) from None

                if nargs > 1 and len(check_default) != nargs:
                    subject = "item length" if multiple else "length"
                    raise ValueError(
                        f"'default' {subject} must match nargs={nargs}."
                    )

        if required and deprecated:
            raise ValueError(
                f"The {self.param_type_name} '{self.human_readable_name}' "
                "is deprecated and still required. A deprecated "
                f"{self.param_type_name} cannot be required."
            )

def to_info_dict(self) -> dict[str, t.Any]:
    """Gather information that could be useful for a tool generating
    user-facing documentation.

    Use :meth:`click.Context.to_info_dict` to traverse the entire
    CLI structure.

    .. versionadded:: 8.0
    """
    return {
        "name": self.name,
        "param_type_name": self.param_type_name,
        "opts": self.opts,
        "secondary_opts": self.secondary_opts,
        "type": self.type.to_info_dict(),
        "required": self.required,
        "nargs": self.nargs,
        "multiple": self.multiple,
        "default": self.default,
        "envvar": self.envvar,
    }

def __repr__(self) -> str:
    return f"<{self.__class__.__name__} {self.name}>"

def _parse_decls(
    self, decls: cabc.Sequence[str], expose_value: bool
) -> tuple[str | None, list[str], list[str]]:
    raise NotImplementedError()

@property
def human_readable_name(self) -> str:
    """Returns the human readable name of this parameter.  This is the
    same as the name for options, but the metavar for arguments.
    """
    return self.name  # type: ignore

def make_metavar(self, ctx: Context) -> str:
    if self.metavar is not None:
        return self.metavar

    metavar = self.type.get_metavar(param=self, ctx=ctx)

    if metavar is None:
        metavar = self.type.name.upper()

    if self.nargs != 1:
        metavar += "..."

    return metavar

@t.overload
def get_default(
    self, ctx: Context, call: t.Literal[True] = True
) -> t.Any | None: ...

@t.overload
def get_default(
    self, ctx: Context, call: bool = ...
) -> t.Any | t.Callable[[], t.Any] | None: ...

def get_default(
    self, ctx: Context, call: bool = True
) -> t.Any | t.Callable[[], t.Any] | None:
    """Get the default for the parameter. Tries
    :meth:`Context.lookup_default` first, then the local default.

    :param ctx: Current context.
    :param call: If the default is a callable, call it. Disable to
        return the callable instead.

    .. versionchanged:: 8.0.2
        Type casting is no longer performed when getting a default.

    .. versionchanged:: 8.0.1
        Type casting can fail in resilient parsing mode. Invalid
        defaults will not prevent showing help text.

    .. versionchanged:: 8.0
        Looks at ``ctx.default_map`` first.

    .. versionchanged:: 8.0
        Added the ``call`` parameter.
    """
    value = ctx.lookup_default(self.name, call=False)  # type: ignore

    if value is None:
        value = self.default

    if call and callable(value):
        value = value()

    return value

def add_to_parser(self, parser: _OptionParser, ctx: Context) -> None:
    raise NotImplementedError()

def consume_value(
    self, ctx: Context, opts: cabc.Mapping[str, t.Any]
) -> tuple[t.Any, ParameterSource]:
    value = opts.get(self.name)  # type: ignore
    source = ParameterSource.COMMANDLINE

    if value is None:
        value = self.value_from_envvar(ctx)
        source = ParameterSource.ENVIRONMENT

    if value is None:
        value = ctx.lookup_default(self.name)  # type: ignore
        source = ParameterSource.DEFAULT_MAP

    if value is None:
        value = self.get_default(ctx)
        source = ParameterSource.DEFAULT

    return value, source

def type_cast_value(self, ctx: Context, value: t.Any) -> t.Any:
    """Convert and validate a value against the option's
    :attr:`type`, :attr:`multiple`, and :attr:`nargs`.
    """
    if value is None:
        return () if self.multiple or self.nargs == -1 else None

    def check_iter(value: t.Any) -> cabc.Iterator[t.Any]:
        try:
            return _check_iter(value)
        except TypeError:
            # This should only happen when passing in args manually,
            # the parser should construct an iterable when parsing
            # the command line.
            raise BadParameter(
                _("Value must be an iterable."), ctx=ctx, param=self
            ) from None

    if self.nargs == 1 or self.type.is_composite:

        def convert(value: t.Any) -> t.Any:
            return self.type(value, param=self, ctx=ctx)

    elif self.nargs == -1:

        def convert(value: t.Any) -> t.Any:  # tuple[t.Any, ...]
            return tuple(self.type(x, self, ctx) for x in check_iter(value))

    else:  # nargs > 1

        def convert(value: t.Any) -> t.Any:  # tuple[t.Any, ...]
            value = tuple(check_iter(value))

            if len(value) != self.nargs:
                raise BadParameter(
                    ngettext(
                        "Takes {nargs} values but 1 was given.",
                        "Takes {nargs} values but {len} were given.",
                        len(value),
                    ).format(nargs=self.nargs, len=len(value)),
                    ctx=ctx,
                    param=self,
                )

            return tuple(self.type(x, self, ctx) for x in value)

    if self.multiple:
        return tuple(convert(x) for x in check_iter(value))

    return convert(value)

def value_is_missing(self, value: t.Any) -> bool:
    if value is None:
        return True

    if (self.nargs != 1 or self.multiple) and value == ():
        return True

    return False

def process_value(self, ctx: Context, value: t.Any) -> t.Any:
    value = self.type_cast_value(ctx, value)

    if self.required and self.value_is_missing(value):
        raise MissingParameter(ctx=ctx, param=self)

    if self.callback is not None:
        value = self.callback(ctx, self, value)

    return value

def resolve_envvar_value(self, ctx: Context) -> str | None:
    if self.envvar is None:
        return None

    if isinstance(self.envvar, str):
        rv = os.environ.get(self.envvar)

        if rv:
            return rv
    else:
        for envvar in self.envvar:
            rv = os.environ.get(envvar)

            if rv:
                return rv

    return None

def value_from_envvar(self, ctx: Context) -> t.Any | None:
    rv: t.Any | None = self.resolve_envvar_value(ctx)

